class Cat extends Animal { speak() { return 'meow' } }

class SerializerFactory {
  serialize(a: Animal) {
    if (a instanceof Dog) return '{dog}'
    if (a instanceof Cat) return '{cat}'
    throw new Error('unknown')
  }
}

